The below example shows how to apply the badge settings for a tab item.
# [XAML](#tab/tabid-1)

<tabView:SfTabView>
    <tabView:SfTabItem BadgeText="45">
        <tabView:SfTabItem.BadgeSettings>
            <core:BadgeSettings TextColor="Red" Position="Left" />
        </tabView:SfTabItem.BadgeSettings>
        <tabView:SfTabItem.Content>
            <Label Text="Content" />
        </tabView:SfTabItem.Content>
    </tabView:SfTabItem>
</tabView:SfTabView>

# [C#](#tab/tabid-2)

var tabView = new SfTabView();
var tabItems = new TabItemCollection
{
    new SfTabItem
    {
        Content = new Label { Text = "Content" },
        BadgeText = "45",
        BadgeSettings = new BadgeSettings 
        {
            TextColor = Colors.Red,
            Position = BadgePosition.Left
        }
    }
};

tabView.Items = tabItems;

***

The below example shows how to apply the spacing between header and image for a tab item.
# [XAML](#tab/tabid-1)

<tabView:SfTabView>
  <tabView:SfTabItem Header = "TAB 1" ImageTextSpacing="2"  ImageSource="avatar1.png"></tabView:SfTabItem>
  <tabView:SfTabItem Header = "TAB 2" ImageTextSpacing="20" ImageSource="avatar1.png"></tabView:SfTabItem>
</tabView:SfTabView>


# [C#](#tab/tabid-2)

var tabView = new SfTabView();
var tabItems = new TabItemCollection
{
    new SfTabItem
    {
        Header = "TAB 1",
        ImageTextSpacing="2"
        ImageSource="avatar1.png"
    }
    new SfTabItem
    {
        Header="TAB 2,
        ImageTextSpacing="20",
        ImageSource="avatar1.png"
    }
};

tabView.Items = tabItems;

***

The below example shows how to initialize the tab view.
# [XAML](#tab/tabid-1)

<tabView:SfTabView x:Name="tabView">
    <tabView:SfTabView.Items>

        <tabView:SfTabItem Header="Item 1">
            <tabView:SfTabItem.Content>
                <Grid BackgroundColor="Red" />
            </tabView:SfTabItem.Content>
        </tabView:SfTabItem>

        <tabView:SfTabItem Header="Item 2">
            <tabView:SfTabItem.Content>
                <Grid BackgroundColor="Green" />
            </tabView:SfTabItem.Content>
        </tabView:SfTabItem>

        <tabView:SfTabItem Header="Item 3">
            <tabView:SfTabItem.Content>
                <Grid BackgroundColor="Blue" />
            </tabView:SfTabItem.Content>
        </tabView:SfTabItem>

    </tabView:SfTabView.Items>
</tabView:SfTabView>

# [C#](#tab/tabid-2)

var tabView = new SfTabView();
Grid allContactsGrid = new Grid { BackgroundColor = Colors.Red };
Grid favoritesGrid = new Grid { BackgroundColor = Colors.Green };
Grid contactsGrid = new Grid { BackgroundColor = Colors.Blue };
var tabItems = new TabItemCollection
{
    new SfTabItem()
    {
        Header = "Item 1",
        Content = allContactsGrid
    },
    new SfTabItem()
    {
        Header = "Item 2",
        Content = favoritesGrid
    },
    new SfTabItem()
    {
        Header = "Item 3",
        Content = contactsGrid
    }
};

tabView.Items = tabItems;
this.Content = tabView;

***

